#include<bits/stdc++.h>
using namespace std;
int a[9],b[9],c[9];
int main(){
    for(int i=1;i<=3;i++){cin>>a[i];b[i]=a[i];}
    sort(b+1,b+4);
    for(int i=1;i<=3;i++)c[i]=pow(b[i],2);
    if(b[1]+b[2]<=b[3]) {cout<<"Not triangle\n";return 0;}
    if(c[1]+c[2]==c[3])cout<<"Right triangle\n";
    else if(c[1]+c[2]>c[3])cout<<"Acute triangle\n";
    else if(c[1]+c[2]<c[3])cout<<"Obtuse triangle\n";
    if(a[1]==a[2]||a[2]==a[3]||a[3]==a[1])cout<<"Isosceles triangle\n";
    if(a[1]==a[2]&&a[2]==a[3])cout<<"Equilateral triangle\n";
	return 0;
}
